component UserCard<T>(user: T, show_email: bool = true) where T: Display {
  signal expanded: bool = false;

  fn toggle(&mut self) {
    self.expanded = !self.expanded;
  }

  style {
    .card { padding: "16px"; border-radius: "8px"; }
  }

  transition {
    opacity: "0.3s ease";
  }

  skeleton {
    <div class="nectar-skeleton nectar-skeleton-rect" />
  }

  render {
    <div class="card">
      <h2>{user.to_string()}</h2>
      {if show_email { <p>{user.email}</p> }}
      <button on:click={self.toggle}>{if self.expanded { "Less" } else { "More" }}</button>
    </div>
  }
}

store_structure.full_example:
store AuthStore {
  signal user: Option<User> = None;
  signal status: AuthStatus = AuthStatus::LoggedOut;

  async action login(&mut self, email: String, password: String) {
    self.status = AuthStatus::Loading;
    let resp = await fetch("/api/login", { method: "POST", body: { email: email, password: password } });
    self.user = Some(resp.json());
    self.status = AuthStatus::LoggedIn(self.user);
  }

  action logout(&mut self) {
    self.user = None;
    self.status = AuthStatus::LoggedOut;
  }

  computed is_logged_in(&self) -> bool {
    match self.status { AuthStatus::LoggedIn(_) => true, _ => false }
  }

  effect on_status_change(&self) {
    println(f"Auth status: {self.status}");
  }
}

agent_structure.full_example:
agent CodeHelper {
  prompt system = "You are a coding assistant. Help users write Arc code.";

  signal messages: [Message] = [];
  signal input: String = "";

  tool search_docs(query: String) -> String {
    let r = await fetch(f"https://docs.example.com/search?q={query}");
    return r.json().summary;
  }

  tool run_code(code: String) -> String {
    let r = await fetch("/api/execute", { method: "POST", body: { code: code } });
    return r.json().output;
  }

  fn send(&mut self) {
    self.messages.push(Message { role: "user", content: self.input });
    self.input = "";
  }

  render {
    <div class="chat">
      {for msg in self.messages { <div class={msg.role}>{msg.content}</div> }}
      <input bind:value={input} on:submit={self.send} />
    </div>
  }
}

