store TodoStore {
  signal todos: [Todo] = [];
  signal filter: Filter = Filter::All;

  action add(&mut self, text: String) {
    self.todos.push(Todo { id: self.todos.len(), text: text, done: false });
  }

  action toggle(&mut self, id: u32) {
    for todo in &mut self.todos {
      if todo.id == id { todo.done = !todo.done; }
    }
  }

  computed visible(&self) -> [Todo] {
    match self.filter {
      Filter::All => self.todos,
      Filter::Active => self.todos.filter(|t| !t.done),
      Filter::Completed => self.todos.filter(|t| t.done),
    }
  }
}

component TodoApp() {
  signal input: String = "";

  fn add(&mut self) {
    TodoStore::add(self.input);
    self.input = "";
  }

  render {
    <div>
      <input bind:value={input} on:submit={self.add} />
      <ul>
        {for todo in TodoStore::visible() {
          <li on:click={|| TodoStore::toggle(todo.id)}>{todo.text}</li>
        }}
      </ul>
    </div>
  }
}

