async fn load_config() -> Result<Config, String> {
  let text = read_file("config.toml")?;
  let config = parse_toml(text)?;
  return Ok(config);
}

component App() {
  signal config: Option<Config> = None;
  signal error: Option<String> = None;

  async fn init(&mut self) {
    try {
      self.config = Some(await load_config()?);
    } catch err {
      self.error = Some(f"Failed to load: {err}");
    }
  }

  render {
    <div>
      {match self.error {
        Some(e) => <div class="error">{e}</div>,
        None => match self.config {
          Some(c) => <ConfigView config={c} />,
          None => <p>"Loading..."</p>,
        },
      }}
    </div>
  }
}

